import json
from pathlib import Path
from datetime import date

def create_internal_eval_task(
    task_description: str,
    input_data: dict,
    expected_output,
    difficulty: str,          # "easy" | "medium" | "hard"
    source: str,              # e.g., "jira-ticket-12345"
    tags: list[str],          # e.g., ["regression", "api-integration"]
) -> dict:
    return {
        "id": f"internal-{date.today()}-{source}",
        "description": task_description,
        "input": input_data,
        "expected_output": expected_output,
        "difficulty": difficulty,
        "source": source,
        "tags": tags,
        "created": str(date.today()),
    }

def run_internal_eval(tasks: list[dict], solve_fn, output_path: str) -> dict:
    results = []
    for task in tasks:
        prediction = solve_fn(task["input"])
        correct = prediction == task["expected_output"]
        results.append({
            "id": task["id"],
            "correct": correct,
            "difficulty": task["difficulty"],
            "tags": task["tags"],
        })

    by_difficulty = {}
    for r in results:
        d = r["difficulty"]
        by_difficulty.setdefault(d, {"correct": 0, "total": 0})
        by_difficulty[d]["total"] += 1
        if r["correct"]:
            by_difficulty[d]["correct"] += 1

    summary = {
        "overall": sum(r["correct"] for r in results) / len(results),
        "by_difficulty": {
            d: v["correct"] / v["total"] for d, v in by_difficulty.items()
        },
        "n_tasks": len(results),
    }
    Path(output_path).write_text(json.dumps({"summary": summary, "results": results}, indent=2))
    return summary

import anthropic, random

client = anthropic.Anthropic()

def multi_turn_robustness_eval(
    task_fn,
    n_turns: int = 6,
    noise_prob: float = 0.2,
    seed: int = 42,
) -> dict:
    """
    Run task_fn as a multi-turn session, randomly injecting misleading
    tool results at noise_prob probability to test error recovery.

    Returns: {"final_passed": bool, "recovered": int, "total_noise": int}
    """
    rng = random.Random(seed)
    messages = []
    recovered = total_noise = 0

    for turn in range(n_turns):
        result = task_fn(messages)
        if result.stop_reason == "end_turn":
            break

        # Inject noise into tool result
        tool_results = []
        for block in result.content:
            if block.type == "tool_use":
                is_noisy = rng.random() < noise_prob
                if is_noisy:
                    total_noise += 1
                    payload = json.dumps({"error": "tool temporarily unavailable"})
                else:
                    payload = json.dumps({"ok": True})
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": payload,
                })

        messages.append({"role": "assistant", "content": result.content})
        messages.append({"role": "user", "content": tool_results})

    final = task_fn(messages)
    passed = "DONE" in (final.content[0].text if final.content else "")
    if total_noise > 0 and passed:
        recovered = total_noise
    return {"final_passed": passed, "recovered": recovered, "total_noise": total_noise}
